advanced_config:
location ~ ^/ {
    auth_basic            "Authorization required";
    auth_basic_user_file  /data/access/1;

    set $target_container "fallback";
    set $target_port "";

    # Regex extracts BOTH the port and the container name
    if ($host ~* ^(?<port>\d+)-(?<container>[a-zA-Z0-9_\-]+)\.sandbox\.ndonet\.nahueldallacamina\.com\.ar$) {
        set $target_container $container;
        set $target_port $port;
    }

    if ($target_container = "fallback") {
        return 404 "Error: Subdomain did not match dynamic routing regex.";
    }

    resolver 127.0.0.11 valid=30s;

    # Dynamically route to the specific port requested in the URL
    proxy_pass http://$target_container:$target_port;

    proxy_set_header Host $host;
    proxy_set_header X-Real-IP $remote_addr;
    proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
    proxy_set_header X-Forwarded-Proto $scheme;

    proxy_http_version 1.1;
    proxy_set_header Upgrade $http_upgrade;
    proxy_set_header Connection $http_connection;
}
